pub fn file_matched(&self) -> bool {
        self.actual_file.as_ref()
            .map(|f| f.ends_with(&self.expect_file) || self.expect_file.ends_with(f.as_str()))
            .unwrap_or(false)
    }
pub fn passed(&self) -> bool {
        self.file_matched() && self.score >= self.min_score
    }
